mapper.select:
SELECT f.faq_dtl_oid, f.faq_ctgry_oid, c.ctgry_nm, f.qstn_cn, f.ans_cn, f.ans_cn_txt, f.sort_seq, f.open_yn, f.use_yn, f.inq_cnt, f.reg_id, f.reg_dt, f.mdfcn_id, f.mdfcn_dt FROM ${schema}.faq_dtl f LEFT JOIN ${schema}.faq_ctgry c ON f.faq_ctgry_oid = c.faq_ctgry_oid
AND f.faq_ctgry_oid = #{faqCtgryOid}
AND ( f.faq_dtl_oid LIKE CONCAT('%', #{keyword}, '%') OR f.qstn_cn LIKE CONCAT('%', #{keyword}, '%') )
AND f.open_yn = #{openYn}
AND DATE_FORMAT(f.reg_dt, '%Y-%m-%d') >= #{regDtSt} AND DATE_FORMAT(f.reg_dt, '%Y-%m-%d') <= #{regDtEd}

mapper.insert:
INSERT INTO ${schema}.faq_dtl (
	faq_ctgry_oid
	, qstn_cn
	, ans_cn
	, ans_cn_txt
	, sort_seq
	, open_yn
	, use_yn
	, inq_cnt
	, reg_id
	, reg_dt
	, mdfcn_id
	, mdfcn_dt
) VALUES (
	#{faqCtgryOid}
	, #{qstnCn}
	, #{ansCn}
	, #{ansCnTxt}
	, COALESCE(#{sortSeq}, 0)
	, #{openYn}
	, 'Y'
	, 0
	, #{regId}
	, NOW()
	, #{regId}
	, NOW()
)

mapper.update:
UPDATE ${schema}.faq_dtl
SET inq_cnt = inq_cnt + 1
WHERE faq_dtl_oid = #{faqDtlOid}

mapper.select:
SELECT f.faq_dtl_oid AS faqDtlOid, c.ctgry_nm AS ctgryNm, f.qstn_cn AS qstn_cn, f.open_yn AS openYn, f.use_yn AS useYn, DATE(f.reg_dt) AS regDt, f.inq_cnt AS inqCnt FROM ${schema}.faq_dtl f LEFT JOIN ${schema}.faq_ctgry c ON f.faq_ctgry_oid = c.faq_ctgry_oid
f.use_yn = 'Y'
AND ( f.faq_dtl_oid LIKE CONCAT('%', #{keyword}, '%') OR f.qstn_cn LIKE CONCAT('%', #{keyword}, '%') )
AND f.open_yn = #{openYn}
AND f.faq_ctgry_oid = #{faqCtgryOid}
AND f.reg_dt >= #{regDtSt}
AND f.reg_dt < DATE_ADD(#{regDtEd}, INTERVAL 1 DAY)
ORDER BY f.sort_seq, f.faq_dtl_oid DESC

